"""HLD Patterns: Scaling Writes, Handling Large Blobs, Managing Long Running Tasks — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def scaling_writes_lesson() -> Lesson:
    return Lesson(id="hld-scaling-writes", number=113, title="Scaling Writes",
        focus=("sharding","write-ahead log","batching","LSM trees","async writes","partitioning"),
        overview="Scaling writes is harder than reads. Know sharding, batching, WAL, and write-optimized storage.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("sw-1","What is the most common approach to scaling writes?","medium",("scaling-writes",),("Indexing","Read replicas","Sharding/partitioning data so writes distribute across multiple nodes","Caching"),2,"Sharding distributes write load. Each shard handles a subset of the total write traffic."),
        quiz("sw-2","Why are LSM trees write-optimized?","hard",("scaling-writes",),("Writes go to in-memory memtable (fast), then flush to sorted SSTables — sequential I/O instead of random","They don't use indexes","They use less memory","They compress data"),0,"LSM trees: O(1) memory writes + sequential disk flushes. Much faster writes than B-trees' random I/O."),
        quiz("sw-3","What is write batching?","medium",("scaling-writes",),("Accumulating multiple writes and committing them together to reduce per-write overhead","A locking mechanism","Writing one row at a time","A caching strategy"),0,"Batching amortizes I/O overhead. Kafka batches messages; databases batch WAL entries."),
        quiz("sw-4","What is write-behind (async write) pattern?","hard",("scaling-writes",),("Synchronous write","A read pattern","A locking technique","Buffer writes in memory/cache, acknowledge to client immediately, flush to storage asynchronously"),3,"Faster ack time but risks data loss if the buffer crashes before flushing."),
        quiz("sw-5","How does Kafka handle high write throughput?","hard",("scaling-writes",),("Append-only log per partition, sequential I/O, batching, zero-copy transfer, and OS page cache","Random writes","Single writer","In-memory only"),0,"Kafka's append-only design with sequential I/O achieves millions of writes/sec per broker."),
        quiz("sw-6","What is write amplification and why does it matter?","hard",("scaling-writes",),("A single logical write causes multiple physical I/O operations (e.g., index updates, LSM compaction)","Writes are too large","A network issue","A caching problem"),0,"B-tree indexes cause write amplification. LSM trees reduce initial write cost but amplify during compaction."),
        quiz("sw-7","What is the hot partition problem for writes?","hard",("scaling-writes",),("Temperature issue","A network issue","A caching problem","One partition receives disproportionate writes, becoming a bottleneck despite overall capacity"),3,"Solution: salt the partition key, split hot partitions, or buffer writes and batch-apply."),
        quiz("sw-8","What is a write-ahead log (WAL)?","hard",("scaling-writes",),("A backup","A query optimizer","Append changes to a sequential log before applying to main storage — ensures durability and enables replication","An index type"),2,"WAL: sequential writes are fast. Main storage updated lazily. Crash recovery replays the log."),
        quiz("sw-9","How does CockroachDB scale writes?","hard",("scaling-writes",),("Caching","Single writer","Read replicas only","Raft-based consensus per range; data auto-sharded across ranges that split when too large"),3,"CockroachDB auto-splits ranges and distributes them. Each range is a Raft group."),
        quiz("sw-10","What is the dual-write problem?","hard",("scaling-writes",),("Writing to two systems (DB + cache/queue) without a transaction can leave them inconsistent if one fails","A performance issue","A UI problem","Writing twice is fine"),0,"Solutions: outbox pattern, CDC, or transactional messaging to ensure both systems stay consistent."),
        quiz("sw-11","What is eventual consistency and how does it help scale writes?","medium",("scaling-writes",),("Data is never consistent","A DB error","Accept that replicas may lag behind; acknowledge writes immediately without waiting for all replicas","Reads return latest write"),2,"Eventual consistency lets you ack writes after 1 replica instead of waiting for all, reducing latency."),
        quiz("sw-12","How do you handle write contention on a single row?","hard",("scaling-writes",),("Lock the entire table","Use atomic operations (INCREMENT, CAS), optimistic locking, or distribute the counter across shards","No solution","Queue all writes"),1,"Sharded counters: split one counter into N shards. Read = SUM(all shards). Reduces contention."),
        quiz("sw-13","What is compaction in LSM trees?","hard",("scaling-writes",),("A backup process","Data compression","Merging and deduplicating sorted SSTables to reclaim space and improve read performance","An indexing step"),2,"Compaction trades write amplification for better read performance and space efficiency."),
        quiz("sw-14","What is the commit log pattern?","medium",("scaling-writes",),("An append-only log of all changes — used by Kafka, databases, and event sourcing systems","An error log","A debug log","A Git log"),0,"Commit logs are the backbone of durable writes. Append-only = fast sequential I/O."),
        quiz("sw-15","How does DynamoDB handle write scaling?","hard",("scaling-writes",),("Auto-partitions data across storage nodes; provisioned or on-demand capacity scales write throughput","Read replicas","Caching","Single node"),0,"DynamoDB auto-splits partitions when throughput exceeds per-partition limits."),
        quiz("sw-16","What is a write-optimized database?","medium",("scaling-writes",),("A cache","Any database","A database designed for high write throughput (Cassandra, ScyllaDB) using LSM trees and append-only storage","A read-heavy DB"),2,"Write-optimized DBs sacrifice read performance for write speed. Read performance recovered via compaction."),
        quiz("sw-17","What is the leaderless replication approach to scaling writes?","hard",("scaling-writes",),("Single leader only","Write to multiple replicas directly (no leader); use quorum reads/writes for consistency","No replication","A caching pattern"),1,"DynamoDB/Cassandra: write to W replicas, read from R replicas. W+R>N ensures overlap."),
        quiz("sw-18","How do you handle burst writes?","medium",("scaling-writes",),("Drop them","Add more indexes","Use a message queue to buffer incoming writes and process them at a sustainable rate","Increase server size"),2,"Queue-based ingestion absorbs burst traffic and smooth writes to the database."),
        quiz("sw-19","What is time-partitioning for write scaling?","medium",("scaling-writes",),("Partition data by time period (hourly/daily tables) so writes always go to the newest partition","A backup schedule","A caching strategy","Sorting by time"),0,"Time-partitioning keeps write hot spot narrow and makes old data easy to archive."),
        quiz("sw-20","What is the change data capture (CDC) pattern for scaling writes?","hard",("scaling-writes",),("A backup tool","A migration tool","Capture DB changes from the WAL and stream them to downstream systems asynchronously","A caching strategy"),2,"CDC enables write scaling by asynchronously updating search indexes, caches, and analytics stores."),
    ))

def large_blobs_lesson() -> Lesson:
    return Lesson(id="hld-large-blobs", number=114, title="Handling Large Blobs",
        focus=("chunked upload","object storage","CDN","content-addressable","pre-signed URLs"),
        overview="Files, videos, and large objects need special handling. Know chunking, object storage, and CDN strategies.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("lb-1","How should you handle large file uploads?","hard",("large-blobs",),("Use FTP","Single request","Chunked upload: split into pieces, upload each with checksum, resume on failure","Compress first"),2,"Chunked upload enables resumability, deduplication, and efficient bandwidth usage."),
        quiz("lb-2","What is content-addressable storage?","hard",("large-blobs",),("Addressing blocks by content hash (SHA-256), enabling deduplication across all users","A CDN type","A database index","Storage by filename"),0,"Same content → same hash → store once, reference many times. Used by Dropbox, Git."),
        quiz("lb-3","What is a pre-signed URL?","medium",("large-blobs",),("A CDN URL","A bookmarked URL","A shortened URL","A time-limited URL granting temporary access to upload/download from object storage without exposing credentials"),3,"Pre-signed URLs let clients upload directly to S3, bypassing your server for large files."),
        quiz("lb-4","Why separate blob storage from metadata storage?","medium",("large-blobs",),("Cost savings only","Performance only","No reason","Blobs are large and best served by object storage (S3); metadata is small and needs indexing/querying (PostgreSQL)"),3,"Object storage: cheap, scalable, CDN-compatible. Database: queryable, consistent, transactional."),
        quiz("lb-5","What is the role of CDN in serving large files?","easy",("large-blobs",),("API routing","Database optimization","Database replication","Caches files at edge locations near users, reducing latency and offloading origin servers"),3,"CDNs serve images, videos, and static files from edge — reducing latency and origin load dramatically."),
        quiz("lb-6","How does chunked upload enable deduplication?","hard",("large-blobs",),("It doesn't","CDN does this","Compression does this","Each chunk is hashed independently; if the hash matches an existing chunk, skip the upload"),3,"Content-defined chunking: even if one byte changes, only affected chunks need re-uploading."),
        quiz("lb-7","What is adaptive bitrate streaming for video?","hard",("large-blobs",),("CDN handles quality","Server adjusts quality","Videos split into chunks at multiple qualities; player switches quality based on bandwidth (HLS/DASH)","One quality"),2,"HLS/DASH: manifest lists chunk URLs at each quality. Player monitors bandwidth and switches dynamically."),
        quiz("lb-8","What is HLS (HTTP Live Streaming)?","hard",("large-blobs",),("Apple's streaming protocol: video split into small .ts segments, served via HTTP, with m3u8 manifest","A database protocol","A CDN feature","A WebSocket variant"),0,"HLS: divide video into 2-10 second segments. Client downloads manifest, then segments sequentially."),
        quiz("lb-9","How does Dropbox sync files efficiently?","hard",("large-blobs",),("Content-defined chunking with rolling hash; only changed chunks are uploaded/downloaded","Email attachments","FTP sync","Full file upload each time"),0,"Rsync-like: detect changed blocks using rolling hash, transfer only deltas."),
        quiz("lb-10","What is the multipart upload pattern in S3?","medium",("large-blobs",),("A backup feature","A versioning system","Multiple files at once","Upload large files in parts independently; S3 assembles them; parts can be retried individually"),3,"Multipart: initiate → upload parts (parallel OK) → complete. Failed parts retry without restarting."),
        quiz("lb-11","What is the difference between S3, GCS, and Azure Blob Storage?","medium",("large-blobs",),("Only S3 is scalable","Functionally similar object stores; S3 API is the de facto standard that GCS/Azure also support","Completely different APIs","They share storage"),1,"S3 is the standard. MinIO provides S3-compatible self-hosted object storage."),
        quiz("lb-12","What is video transcoding and why is it needed?","medium",("large-blobs",),("CDN caching","A streaming protocol","Video compression only","Converting uploaded video into multiple formats/resolutions for different devices and network conditions"),3,"Transcode to 480p/720p/1080p/4K + different codecs (H.264, VP9, AV1) for universal playback."),
        quiz("lb-13","How do you handle image resizing at scale?","hard",("large-blobs",),("Store every size","Let the client resize","Generate on-demand and cache: when a size is first requested, resize, cache in CDN, serve cached thereafter","Store originals only"),2,"On-demand resizing with CDN caching: URL like /images/photo.jpg?w=300&h=300 → resize → cache."),
        quiz("lb-14","What is the thumbnail generation pattern?","medium",("large-blobs",),("Upload → async job generates thumbnails at standard sizes → store in object storage → serve via CDN","Real-time generation","Manual creation","Client-side generation"),0,"Async processing: upload triggers a job queue. Workers generate thumbnails. CDN serves them."),
        quiz("lb-15","What is the challenge of serving large files globally?","medium",("large-blobs",),("Cost only","File size","Latency — files must be cached at edge locations worldwide; origin requests must be minimized","Security"),2,"CDN + multi-region replication + intelligent cache warming for popular content."),
        quiz("lb-16","How does YouTube handle video storage at scale?","hard",("large-blobs",),("One server","Local disk","Distributed object storage with redundancy, multiple encoded versions per video, CDN for delivery","A single data center"),2,"Google's Colossus stores video. Each video has multiple bitrate versions. Served from global CDN."),
        quiz("lb-17","What is the garbage collection challenge in blob storage?","hard",("large-blobs",),("A CDN issue","Identifying and deleting orphaned blobs (referenced chunks with no parent, or deleted files' chunks)","Memory management","A network problem"),1,"If metadata is deleted but blob isn't (or vice versa), you leak storage or break references."),
        quiz("lb-18","What is the role of checksums in blob storage?","medium",("large-blobs",),("Encryption","Deduplication only","Verify data integrity during upload, transfer, and storage — detect corruption or tampering","Compression"),2,"MD5/SHA-256 checksums ensure the file you uploaded is the exact file stored and served."),
        quiz("lb-19","How do you implement resumable uploads?","hard",("large-blobs",),("Use FTP","Track uploaded chunks on server; client queries which chunks are missing and uploads only those","Cache the upload","Start over on failure"),1,"Client: upload chunk → get ack. On failure: ask server which chunks received → resume from there."),
        quiz("lb-20","What is the difference between hot and cold storage tiers?","medium",("large-blobs",),("Hot is older data","Cold is more secure","Hot: frequently accessed, fast, expensive (SSD/S3 Standard). Cold: rarely accessed, slow, cheap (S3 Glacier)","Temperature of servers"),2,"Lifecycle policies auto-move old data to cheaper tiers. Access old data with higher latency."),
    ))

def long_running_tasks_lesson() -> Lesson:
    return Lesson(id="hld-long-tasks", number=115, title="Managing Long Running Tasks",
        focus=("job queues","workers","idempotency","progress tracking","timeouts","dead letter queues"),
        overview="Long-running tasks (video processing, reports, ML inference) need special architecture patterns.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("lt-1","How should you handle a request that takes minutes to process?","medium",("long-tasks",),("Use faster server","Make client wait","Return 202 Accepted with a job ID; process async; client polls for status or receives webhook callback","Increase timeout"),2,"Never block a client for minutes. Accept the request, process in background, notify when done."),
        quiz("lt-2","What is a job/task queue?","easy",("long-tasks",),("A load balancer","A cache","A database","A queue where producers submit jobs and workers consume and process them asynchronously"),3,"Job queues (Celery, Sidekiq, Bull) decouple request handling from processing."),
        quiz("lt-3","What is the competing consumers pattern?","medium",("long-tasks",),("Multiple workers read from the same queue, each processing different jobs for parallelism","Multiple caches","A conflict strategy","A database pattern"),0,"Add more workers to increase throughput. Each job processed by exactly one worker."),
        quiz("lt-4","How do you handle worker failures?","hard",("long-tasks",),("Delete the job","Ignore them","Restart the server","Use visibility timeouts: if worker doesn't ack within timeout, job returns to queue for another worker"),3,"SQS visibility timeout: job is invisible while processing. If no ack, it reappears for retry."),
        quiz("lt-5","What is a dead letter queue?","medium",("long-tasks",),("A logging mechanism","A backup queue","Where jobs that fail after max retries are sent for investigation and manual handling","A deleted queue"),2,"DLQs prevent poison messages from blocking the queue forever."),
        quiz("lt-6","How do you track progress of long-running tasks?","medium",("long-tasks",),("Email updates","Store progress in a fast store (Redis); expose a status endpoint; optionally push updates via WebSocket","No tracking needed","Check logs"),1,"Job writes progress (30%, 50%, 90%) to Redis. Client polls /jobs/{id}/status or subscribes via WS."),
        quiz("lt-7","What is the fan-out/fan-in pattern for long tasks?","hard",("long-tasks",),("Split a large task into many subtasks (fan-out), process in parallel, aggregate results (fan-in)","A caching strategy","A database pattern","A load balancing technique"),0,"Map-Reduce is a classic fan-out/fan-in. Video transcoding: split into chunks → process → merge."),
        quiz("lt-8","Why must long-running tasks be idempotent?","hard",("long-tasks",),("A performance issue","A UI concern","Not necessary","Workers may crash and jobs get retried — without idempotency, you get duplicate processing/side effects"),3,"Idempotent tasks are safe to retry. Use a unique job ID to detect and skip duplicates."),
        quiz("lt-9","What is a priority queue for long tasks?","medium",("long-tasks",),("A database feature","A caching strategy","FIFO only","A queue where jobs are processed based on priority level, not just arrival order"),3,"High-priority jobs (paid users, time-sensitive) get processed before low-priority (batch reports)."),
        quiz("lt-10","How do you handle job timeouts?","hard",("long-tasks",),("No timeouts","Let it run forever","Set a maximum execution time; if exceeded, kill the worker, mark job as failed, retry or move to DLQ","Increase timeout infinitely"),2,"Timeouts prevent zombie workers from holding resources. Set reasonable limits per job type."),
        quiz("lt-11","What is the circuit breaker pattern for long tasks?","hard",("long-tasks",),("A database feature","If a downstream service repeatedly fails, stop submitting jobs to it temporarily, fail fast instead","A queue pattern","A hardware device"),1,"Circuit breaker: open after N failures → fail fast → half-open after cooldown → test → close."),
        quiz("lt-12","How does video transcoding use long-running task patterns?","hard",("long-tasks",),("Client-side processing","Real-time transcoding","Single-threaded processing","Upload → queue → worker splits video into chunks → parallel transcoding → merge → store → notify"),3,"Fan-out/fan-in: each chunk transcoded independently. Horizontally scalable with more workers."),
        quiz("lt-13","What is exponential backoff for job retries?","medium",("long-tasks",),("Constant retry interval","Wait increasing durations between retries (1s, 2s, 4s, 8s...) with jitter to avoid synchronized retries","Linear backoff","No retry"),1,"Exponential backoff reduces load on failing services. Jitter prevents retry storms."),
        quiz("lt-14","What is the scheduler pattern for recurring long tasks?","medium",("long-tasks",),("Manual execution","A service that triggers jobs at scheduled times (cron-like) using a distributed scheduler","A cache warmer","A load balancer"),1,"Distributed schedulers (Celery Beat, Airflow) ensure jobs run on time across multiple nodes."),
        quiz("lt-15","How do you ensure exactly-once job processing?","hard",("long-tasks",),("At-least-once delivery + idempotent workers: use job ID deduplication to skip already-processed jobs","Use 2PC","Impossible","Single worker only"),0,"Store completed job IDs. Before processing, check if ID exists. If yes, skip."),
        quiz("lt-16","What is the poison message problem?","hard",("long-tasks",),("A security issue","A database corruption","A network error","A message that causes worker crashes on every attempt, blocking the queue for all other messages"),3,"Solutions: max retry count + DLQ. After N failures, move to DLQ for investigation."),
        quiz("lt-17","How do you scale video processing workers?","medium",("long-tasks",),("One big server","Fixed worker count","Auto-scale worker fleet based on queue depth; more pending jobs = more workers","Client-side processing"),2,"Cloud auto-scaling: monitor queue length. Scale up when queue grows. Scale down when queue drains."),
        quiz("lt-18","What is the bulkhead pattern for long tasks?","hard",("long-tasks",),("A caching strategy","Isolate different task types into separate queues/worker pools so one type's failure doesn't affect others","A sharding technique","A storage pattern"),1,"Separate queues for video, image, report processing. Failure in video queue doesn't block images."),
        quiz("lt-19","What is a workflow orchestrator (Temporal/Airflow)?","hard",("long-tasks",),("A platform managing complex multi-step workflows with built-in state persistence, retry, and timeout handling","A load balancer","A CI/CD tool","A database"),0,"Temporal: define workflows as code. Handles retries, timeouts, compensation, and state automatically."),
        quiz("lt-20","What is the difference between synchronous and asynchronous task execution?","easy",("long-tasks",),("Sync: caller waits for result. Async: caller gets immediate response; result delivered later via callback/poll","Sync is always faster","Async doesn't produce results","No difference"),0,"Rule of thumb: if it takes >1s, make it async. Never block an HTTP handler for minutes."),
    ))
